from agent import *from models.products import *def run(context, session):    session.queue(Request("https://www.coachmag.co.uk/reviews"), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath("//article[parent::a]")    for rev in revs:        name = rev.xpath("following::h3[1]//text()").string(multiple=True)        url = rev.xpath("parent::a/@href").string()        session.queue(Request(url), process_review, dict(name=name, url=url))    if not revs:        cats = data.xpath("//li[@class='allcategories item--full']//a")        for cat in cats:            url = cat.xpath("@href").string()            session.queue(Request(url), process_revlist, dict())        if not cats:            revs = data.xpath("//li[@class='day-article']//a")            for rev in revs:                name = rev.xpath("text()").string()                url = rev.xpath("@href").string()                session.queue(Request(url), process_review, dict(name=name, url=url))    next_url = data.xpath("//div[@class='flexi-pagination']//span[@class='active']/following-sibling::a[1]/@href").string()    if next_url:        session.queue(Request(next_url), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = context["name"].split(" Review")[0]    product.url = context["url"]    product.ssid = context["url"].split('/')[-1]    if "/page/" in context["url"]:        product.ssid = context["url"].split('/')[-4] + '-' + context["url"].split('/')[-1]    product.category = data.xpath("//nav[@class='breadcrumb']/following::ol[1]/li[position()>1]//a/text()").join('|') or context["url"].split('/')[3].title()    review = Review()    review.type = "pro"    review.title = context["name"]    review.url = context["url"]    review.ssid = product.ssid    date = data.xpath("//time/@datetime").string()    if date:        review.date = date.split('T')[0]    grade_overall = data.xpath("//span[contains(@class, 'rating')]").first()    if grade_overall:        stars = len(grade_overall.xpath("span[@class='icon icon-star']"))        half_stars = len(grade_overall.xpath("span[@class='icon icon-star half']"))        review.grades.append(Grade(type="overall", value=float(stars+half_stars/2), best=5.0))    author = data.xpath("//a[@rel='author']").first()    if author:        name = author.xpath(".//text()").string(multiple=True)        url = author.xpath("@href").string()        review.authors.append(Person(name=name, ssid=name, profile_url=url))    pros = data.xpath("//h4[contains(@class, 'icon-plus_circle')]/following-sibling::ul[1]/li/span/text()").strings()    for pro in pros:        pro = pro.strip()        if pro:            review.add_property(type="pros", value=pro)    cons = data.xpath("//h4[contains(@class, 'icon-minus_circle')]/following-sibling::ul[1]/li/span/text()").strings()    for con in cons:        con = con.strip()        if con:            review.add_property(type="cons", value=con)    excerpt = data.xpath("//div[@id='article-body']//p[not(regexp:test(., '^buy from', 'i'))]//text()").string(multiple=True)    next_page = data.xpath("//div[@class='flexi-pagination']//span[@class='active']/following-sibling::a[1]/@href").string()    if next_page:        if excerpt:            review.add_property(type="summary", value=excerpt)        session.do(Request(next_page), process_lastpage, dict(product=product, review=review, url=next_page))        return    summary = data.xpath("//div[@class='header-sub-container']//h2//text()").string(multiple=True)    if summary:        review.add_property(type="summary", value=summary)    conclusion = data.xpath("//div[contains(@class, 'verdict')]//p//text()").string(multiple=True)    if conclusion:        review.add_property(type="conclusion", value=conclusion)    if excerpt:        review.add_property(type="excerpt", value=excerpt)        product.reviews.append(review)        session.emit(product)def process_lastpage(data, context, session):    product = context["product"]    review = context["review"]    page = data.xpath("//span[@class='active']/text()").string()    review.add_property(type="pages", value=dict(url=context["url"], title=product.name+'-'+str(page)))    next_page = data.xpath("//div[@class='flexi-pagination']//span[@class='active']/following-sibling::a[1]/@href").string()    if next_page:        session.do(Request(next_page), process_lastpage, dict(context, url=next_page))        return    conclusion = data.xpath("//div[@id='article-body']//p[not(regexp:test(., '^buy from', 'i'))]//text()").string(multiple=True)    if conclusion:        review.add_property(type="conclusion", value=conclusion)    product.reviews.append(review)    session.emit(product)